function rail(c){return `<nav class="left-nav"><div class="module-links">${NAV_ITEMS.map(([x,i])=>`<button class="nav-button ${x==="Portfolio"?"active":""}"><span class="nav-icon">${icon(i)}</span><span class="nav-text">${x}</span>${x==="Alerts"?`<b>${c.alerts.length}</b>`:""}</button>`).join("")}</div><section class="rail-summary"><strong>Operational status</strong><div><span><i></i>Complete</span><b>${c.operational_status.successful_strategy_count}</b></div><div><span><i class="pending"></i>Pending</span><b>1</b></div><div><span><i class="warning"></i>Alerts</span><b>${c.alerts.length}</b></div><div class="rail-ring"><span>${c.portfolio_summary.current_n}<small>ACTIVE</small></span></div><dl><dt>Live allocation</dt><dd>0%</dd><dt>Execution</dt><dd>Disabled</dd><dt>Mode</dt><dd>Research</dd></dl></section></nav>`}
function commandSpark(values,tone){const nums=values.map(Number).filter(Number.isFinite);if(nums.length<2)return "";const min=Math.min(...nums),max=Math.max(...nums),range=max-min||1,points=nums.map((v,i)=>`${(i/(nums.length-1)*100).toFixed(1)},${(20-(v-min)/range*16).toFixed(1)}`).join(" ");return `<svg class="sparkline tone-${tone}" viewBox="0 0 100 22" preserveAspectRatio="none" aria-hidden="true"><polyline class="spark-stroke command-spark" points="${points}"></polyline></svg>`}
function commandMetricCard({label,value,detail,tone,status,values}){const spark=Array.isArray(values)&&values.length>1?commandSpark(values,tone):"";return `<article class="metric-card"><div class="metric-head"><span class="metric-label">${label}</span><b class="metric-status tone-${tone}">${status}</b></div><div class="metric-main"><strong class="metric-value tone-${tone}">${value}</strong>${spark}</div><span class="metric-detail">${detail}</span></article>`}
function metrics(c){const s=c.portfolio_summary,d=c.portfolio_daily,cr=c.capital_reconciliation||{},inv=c.strategy_entity_inventory||{},intr=c.intraday_estimate||{},cost=d.reduce((n,r)=>n+Number(r.transaction_cost||0),0),nav=d.map(r=>r.ending_nav),daily=d.map(r=>r.net_pnl),cum=d.map(r=>r.cumulative_pnl),costs=d.map(r=>r.transaction_cost),verified=s.verified_shadow_start_label??"Not Yet Established",cards=[["Official NAV",UI.money(s.official_daily_nav??s.nav),`Official Daily Ledger through ${c.official_daily?.latest_official_close_date||s.as_of_date}`,"positive","OFFICIAL",nav],["Intraday Estimated NAV",UI.money(s.intraday_estimated_nav),intr.market_data_as_of||"Delayed price pending",UI.toneForNumber(s.intraday_estimated_pnl),"DELAYED",null],["Intraday Estimated P&L",UI.money(s.intraday_estimated_pnl),"Not Official Ledger",UI.toneForNumber(s.intraday_estimated_pnl),"ESTIMATE",null],["Official Daily P&L",UI.money(s.official_daily_pnl??s.latest_net_pnl),s.as_of_date,UI.toneForNumber(s.official_daily_pnl??s.latest_net_pnl),"OFFICIAL",daily],["Official Cumulative P&L",UI.money(s.cumulative_pnl),UI.percent(s.cumulative_return,3),"positive","OFFICIAL",cum],["Transaction costs",UI.money(cost),"Operational record cumulative","warning","5 BPS",costs],["Ordinary Active",inv.ordinary_operational_ledgers??"N/A","16 standalone active strategies","info","LEDGERS",null],["Current Top-Level ACTIVE",cr.top_level_active_sleeves??"N/A",`16 ordinary + Combined; top sleeve ${UI.percent(cr.top_level_sleeve_weight,2)}`,"info","COUNT",null],["Pending Candidates",c.pending_membership?1:0,"#000018 current sleeve N/A","pending","PENDING",null],["Verified Shadow-Live Start",verified,"Complete provenance required","warning","PROVENANCE",null]];return `<section class="metric-grid">${cards.map(x=>commandMetricCard({label:x[0],value:String(x[1]),detail:x[2],tone:x[3],status:x[4],values:x[5]})).join("")}</section>`}
function allocation(c){const active=c.strategies.filter(r=>r.membership_state==="executed"),colors=active.map((_,i)=>`hsl(${Math.round(i*360/active.length+185)%360} 68% 52%)`),step=100/active.length,gradient=colors.map((color,i)=>`${color} ${(i*step).toFixed(3)}% ${((i+1)*step).toFixed(3)}%`).join(","),cr=c.capital_reconciliation||{};return UI.Panel({title:"Current membership & allocation",meta:`${cr.top_level_active_sleeves??active.length} current top-level sleeves; WQ current sleeve N/A`,className:"allocation-panel",body:`<div class="allocation-body"><div class="allocation-donut" style="--donut-gradient:conic-gradient(${gradient})"><div><strong>${cr.top_level_active_sleeves??active.length}</strong><span>ACTIVE</span></div></div><div class="allocation-list">${active.slice(0,8).map((r,i)=>`<div class="allocation-row"><span><i style="background:${colors[i]}"></i>${r.ui_name}</span><b>${UI.percent(r.current_weight,2)}</b><em style="background:${colors[i]}"></em></div>`).join("")}</div></div><div class="allocation-summary"><strong>Master Portfolio</strong><span>${c.portfolio_summary.portfolio_id}</span><b>${UI.money(c.portfolio_summary.nav)}</b></div><div class="panel-footer"><span>${active.length} active top-level rows: 16 ordinary + Combined</span><strong>${UI.percent(cr.top_level_sleeve_weight,2)}</strong><span>Pending proposed sleeve ${UI.percent(cr.pending_post_admission_sleeve_weight,2)}</span></div>`})}
