function monitorEntities(){return state.contract.strategies.map(s=>({...s,ui_name:s.display_name||s.ui_name||s.name}))}
function monitorFiltered(){const q=state.strategyFilter.toLowerCase(),rows=monitorEntities().filter(r=>(!q||r.ui_name.toLowerCase().includes(q)||r.display_id.toLowerCase().includes(q)||r.family.toLowerCase().includes(q))&&(!state.membershipFilter||r.membership_state===state.membershipFilter)&&(!state.familyFilter||r.family===state.familyFilter)&&(!state.dataFilter||r.data_status===state.dataFilter));return rows.sort((a,b)=>{if(a.internal_id==="COMBINED_PORTFOLIO"&&b.internal_id!=="COMBINED_PORTFOLIO")return -1;if(b.internal_id==="COMBINED_PORTFOLIO"&&a.internal_id!=="COMBINED_PORTFOLIO")return 1;const av=a[state.sortKey],bv=b[state.sortKey];if(av==null&&bv==null)return 0;if(av==null)return 1;if(bv==null)return -1;return (typeof av==="number"?av-bv:String(av).localeCompare(String(bv)))*state.sortDir})}
