function drawBars(canvas,vals){if(!canvas||vals.length<2)return;const ctx=canvas.getContext("2d"),w=canvas.width,h=canvas.height,p=24,max=Math.max(...vals.map(v=>Math.abs(Number(v))),1),zero=h/2,bw=Math.max(3,(w-p*2)/vals.length*.62);ctx.clearRect(0,0,w,h);ctx.strokeStyle="#27434a";ctx.beginPath();ctx.moveTo(p,zero+.5);ctx.lineTo(w-p,zero+.5);ctx.stroke();vals.forEach((v,i)=>{const n=Number(v),x=p+(i+.5)*(w-p*2)/vals.length,bh=Math.abs(n)/max*(h/2-p);ctx.fillStyle=n>=0?"#23d477":"#ff4f3d";ctx.fillRect(x-bw/2,n>=0?zero-bh:zero,bw,bh)})}
