function toast(message,tone="info"){const el=document.getElementById("commandToast");if(!el)return;el.textContent=message;el.className=`command-toast show ${tone}`;setTimeout(()=>el.classList.remove("show"),3500)}
function openPortfolioPoint(index){const r=state.contract.portfolio_daily[index],drawer=document.getElementById("detailDrawer");if(!r||!drawer)return;state.drawerOpen=false;document.getElementById("drawerTitle").textContent=`Portfolio interval ${r.date}`;document.getElementById("drawerSubtitle").textContent="OFFICIAL_DAILY immutable reconciled record";document.getElementById("drawerTabs").innerHTML="";const rows=state.contract.strategies.filter(s=>s.daily_pnl!=null).sort((a,b)=>Math.abs(b.daily_pnl)-Math.abs(a.daily_pnl)).slice(0,8);document.getElementById("drawerBody").innerHTML=`<div class="drawer-kpis"><div><span>Ending NAV</span><strong>${UI.money(r.ending_nav)}</strong></div><div><span>Gross P&L</span><strong>${UI.money(r.gross_pnl)}</strong></div><div><span>Cost</span><strong>${UI.money(r.transaction_cost)}</strong></div><div><span>Net P&L</span><strong class="tone-${UI.toneForNumber(r.net_pnl)}">${UI.money(r.net_pnl)}</strong></div></div><section class="drawer-panel"><header><strong>Latest available strategy contribution</strong><span>Interval-specific history unavailable where not canonical</span></header><table class="mini-table"><tbody>${rows.map(s=>`<tr><td>${s.ui_name}</td><td class="tone-${UI.toneForNumber(s.daily_pnl)}">${UI.money(s.daily_pnl)}</td><td>${s.data_status}</td></tr>`).join("")}</tbody></table></section><section class="drawer-panel"><header><strong>Data warnings</strong><span>Reconciliation residual</span></header><div class="na-block"><strong>${r.current_drawdown==null?"INSUFFICIENT HISTORY":"RECONCILED"}</strong><span>Security attribution and interval trades remain N/A unless present in the operational ledger.</span><div><b>Residual</b><em>N/A</em></div></div></section>`;drawer.classList.add("open");drawer.setAttribute("aria-hidden","false")}
async function loadSnapshot(){const r=await fetch(`/api/operational-snapshot?ts=${Date.now()}`,{cache:"no-store",headers:{"Cache-Control":"no-store"}});if(!r.ok)throw new Error(`Operational snapshot unavailable (${r.status})`);const snapshot=await r.json();state.contract=snapshot;state.nextRefreshAt=snapshot.next_refresh?Date.parse(snapshot.next_refresh):Date.now()+POLL_INTERVAL_MS;enrich(state.contract);return snapshot}
async function refreshOperational(manual=false){if(state.refreshState==="REFRESHING")return;state.refreshState="REFRESHING";render();try{const r=await fetch(`/api/refresh?ts=${Date.now()}`,{method:"POST",cache:"no-store",headers:{"Content-Type":"application/json","Cache-Control":"no-store"},body:JSON.stringify({trigger:manual?"manual":"automatic_poll"})}),result=await r.json();if(!r.ok&&!result.snapshot_id)throw new Error(result.error||`Refresh failed (${r.status})`);const snapshot=await loadSnapshot();state.refreshState=snapshot.refresh_status||"SUCCESS";state.nextRefreshAt=snapshot.next_refresh?Date.parse(snapshot.next_refresh):Date.now()+POLL_INTERVAL_MS;render();toast(manual?"Manual refresh completed":"Automatic five-minute refresh completed",snapshot.refresh_status==="STALE"?"warning":"positive")}catch(e){state.refreshState="STALE";await loadSnapshot().catch(()=>{});render();toast(`Refresh stale: ${e.message}`,"warning")}}
async function submitDecision(action){if(state.decisionBusy)return;const reviewer=prompt(`${action} reviewer`,"RM");if(!reviewer)return;const rationale=prompt(`${action} rationale`,"Human governance review");if(!rationale)return;let newWeights;if(action==="MODIFY"){const seed=JSON.stringify(state.contract.proposal_state?.proposed_weights||{},null,2),raw=prompt("Edit proposed weights as JSON. Values must sum to 1.0.",seed);if(!raw)return;try{newWeights=JSON.parse(raw)}catch(e){toast("Invalid weight JSON","negative");return}}state.decisionBusy=true;render();try{const r=await fetch("/api/decisions",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action,reviewer,rationale,new_proposed_weights:newWeights,proposed_effective_date:state.contract.pending_membership?.effective_from})}),result=await r.json();if(!r.ok)throw new Error(result.error||"Decision failed");state.contract=result.snapshot;enrich(state.contract);toast(`${action} recorded locally`,"positive")}catch(e){toast(e.message,"negative")}finally{state.decisionBusy=false;render()}}
async function init(){window.__phase1Metrics={pollIntervalMs:POLL_INTERVAL_MS};await loadSnapshot();render();state.pollTimer=setInterval(()=>refreshOperational(false),POLL_INTERVAL_MS)}
init().catch(e=>{document.getElementById("app").innerHTML=`<div class="fatal-state"><strong>Canonical data unavailable</strong><span>${UI.escapeHtml(e.message)}</span></div>`;console.error(e)});
